# Very short cleaned version

```javascript
const config = {
  repulsion: 4000,
  cameraLerp: 0.004,
  damping: 0.92,
  centerPull: 0.0003,
  maxParticles: 40,
  particleDrag: 0.04,
  springK: 0.06
};

const points = [/* 6 graph nodes */];
const links = [/* spring connections */];
const particles = [];
const lens = { x: 400, y: 300, zoom: 1 };
const focus = { x: 400, y: 300, zoom: 1 };
let tick = 0;

function pointById(id) {
  return points.find(p => p.id === id) || null;
}

function updatePhysics() {
  for (let i = 0; i < points.length; i++) {
    for (let j = i + 1; j < points.length; j++) {
      const dx = points[i].x - points[j].x;
      const dy = points[i].y - points[j].y;
      const d = Math.sqrt(dx * dx + dy * dy) || 1;
      const f = config.repulsion / (d * d);
      const fx = dx / d * f;
      const fy = dy / d * f;
      points[i].vx += fx; points[i].vy += fy;
      points[j].vx -= fx; points[j].vy -= fy;
    }
  }

  for (const link of links) {
    const a = pointById(link.a);
    const b = pointById(link.b);
    if (!a || !b) continue;

    const dx = b.x - a.x;
    const dy = b.y - a.y;
    const d = Math.sqrt(dx * dx + dy * dy) || 1;
    const stretch = d - link.rest;
    const f = (link.k || config.springK) * stretch;

    a.vx += dx / d * f; a.vy += dy / d * f;
    b.vx -= dx / d * f; b.vy -= dy / d * f;
  }

  for (const p of points) {
    p.vx += (400 - p.x) * config.centerPull;
    p.vy += (300 - p.y) * config.centerPull;
    p.vx *= config.damping;
    p.vy *= config.damping;
    p.x += p.vx;
    p.y += p.vy;
  }
}

function emitParticle() {
  if (particles.length >= config.maxParticles) return;
  const src = points[Math.floor(Math.random() * points.length)];
  const angle = Math.random() * Math.PI * 2;
  const speed = 0.3 + Math.random() * 0.707;

  particles.push({
    x: src.x,
    y: src.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * 1.618 * 0.707
  });
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i];
    p.x += p.vx;
    p.y += p.vy;
    p.vx *= 1 - config.particleDrag * 0.125;
    p.vy *= 1 - config.particleDrag * 0.125;
    p.age++;
    if (p.age > p.maxAge) particles.splice(i, 1);
  }
}

function updateLens() {
  lens.x += (focus.x - lens.x) * config.cameraLerp;
  lens.y += (focus.y - lens.y) * config.cameraLerp;
  lens.zoom += (focus.zoom - lens.zoom) * config.cameraLerp;
}

function pulse() {
  updatePhysics();
  updateParticles();
  updateLens();
  if (tick % 3 === 0) emitParticle();
  tick++;
}

setInterval(pulse, 16);
```

